// AUTO-GENERATED by workflow — art. Do not hand-edit; re-run integrate.mjs.
// ──────────────────────────────────────────────────────────────────────────
// equipment_gear — ENHANCED EDITION (art_v2)
// Shiny inventory icons for GEAR / armor + trinkets.
//   • brushed metal gradients (gradV/gradH) with a top-left specular glint
//   • glowing gems (p.glow) with white catch-lights
//   • leather sheen + stitched seams
//   • per-rarity "kira" sparkle (p.star4 / p.sparkle) so loot reads as loot
// All sprite NAMES, sizes (16x16) and anchors are unchanged — drop-in safe.
// ──────────────────────────────────────────────────────────────────────────
import { defineSprite, defineAnim, Painter } from '../../engine/sprites.js';
import { P, lighten, darken, mix, withAlpha, tint } from '../../engine/palette.js';
import { defineIcon, panel, sym } from '../icons.js';
import { drawSlime, drawBat, drawWisp, drawBrute, drawHunter } from '../core.js';

// ==== equipment_gear icons (armor x4 + trinket x4) ====

// ── shared shine helpers (self-contained: Painter + sym + P + helpers) ──────

// Brushed-metal body: vertical core->shadow gradient, soft top sheen band,
// and a couple of vertical "brush" streaks. Returns nothing; draws in-place.
function _metalBody(p, x, y, w, h, metal) {
  p.gradV(x, y, w, h, lighten(metal, 0.22), darken(metal, 0.28));
  // top sheen band
  p.rect(x, y, w, 1, lighten(metal, 0.42));
  // vertical brush streaks (cool sheen lines)
  p.vline(y + 1, y + h - 2, x + 1, lighten(metal, 0.3));
  p.vline(y + 1, y + h - 2, x + Math.round(w * 0.62), darken(metal, 0.16));
}

// A faceted glowing gem: outer glow halo, body gradient, white catch-light.
function _gem(p, cx, cy, rx, ry, gem, glowCol) {
  p.glow(cx, cy, Math.max(rx, ry) + 1.6, glowCol || lighten(gem, 0.3), 0.5, 4);
  p.ellipse(cx, cy, rx, ry, darken(gem, 0.28));
  p.ellipse(cx, cy, rx - 0.7, ry - 0.7, gem);
  // upper-left facet highlight
  p.ellipse(cx - 0.6, cy - 0.7, rx * 0.45, ry * 0.45, lighten(gem, 0.4));
  p.px(Math.round(cx - rx * 0.4), Math.round(cy - ry * 0.4), P.white);
}

// Rarity sparkle: a kira-star + a couple of small twinkles in a corner.
function _rarity(p, col = P.holyL, x = 12, y = 4) {
  p.star4(x, y, 3, col, P.white);
  p.sparkle(4, 12, withAlpha(col, 0.9), 1);
  p.px(3, 4, withAlpha(P.white, 0.85));
}

function _gearShield(p, c, cD, cL) {
  for (let y = 3; y <= 12; y++) {
    const t = (y - 3) / 9;
    const w = 4.4 * (1 - t * 0.5) * (y > 9 ? (13 - y) / 3.5 : 1);
    p.hline(8 - w, 7 + w, y, t < 0.45 ? mix(c, cL, 0.25 * (1 - t)) : cD);
  }
  p.hline(5, 10, 3, cL);
  p.vline(4, 9, 8, lighten(c, 0.25));
  p.px(6, 4, P.rim);
}

function _gearRing(p, metal, gem) {
  // metallic band with bright top arc + dark underside
  p.ring(8, 9, 3.3, lighten(metal, 0.15));
  p.ring(8, 9, 2.5, darken(metal, 0.3));
  // top arc sheen
  p.px(8, 6, lighten(metal, 0.5));
  p.px(6, 7, lighten(metal, 0.35));
  p.px(10, 7, lighten(metal, 0.35));
  // underside shade
  p.px(8, 12, darken(metal, 0.4));
  _gem(p, 8, 5, 1.7, 1.7, gem, lighten(gem, 0.35));
}

// ---- armor -----------------------------------------------------------------
// 重甲：厚重鋼板甲 — polished steel plate with a glinting trim
defineIcon('equip_g_heavy_plate', P.steelD, (p) => {
  for (let y = 3; y <= 13; y++) {
    const t = (y - 3) / 10;
    const w = 5 * (1 - t * 0.22);
    // vertical tonal ramp: bright top -> deep steel bottom
    const col = mix(lighten(P.steel, 0.3), P.steelD, t * 1.05);
    p.hline(8 - w, 7 + w, y, col);
  }
  // pauldron / collar block with sheen
  p.gradV(6, 3, 4, 3, P.steelL, P.iron);
  // central ridge + rivet line
  p.vline(4, 13, 8, lighten(P.steel, 0.18));
  p.hline(3, 12, 7, darken(P.steelD, 0.25));
  // rivets
  p.px(5, 6, P.steelL); p.px(11, 6, darken(P.steelD, 0.2));
  p.px(5, 10, P.iron);  p.px(11, 10, P.iron);
  // specular glints (top-left light)
  p.px(5, 4, P.rim); p.px(6, 5, P.glint);
  p.px(10, 9, P.steelL);
  p.rimLight(P.rimCool, 0.5);
  p.softShadow(8, 14, 5, 1.2, 0.35);
  p.sparkle(12, 4, withAlpha(P.steelL, 0.9), 1);
});

// 刺甲：帶尖刺的鐵甲 — dark iron mail bristling with razor spikes
